#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5;

struct Edge{
	int to,val;
};

bool operator<(Edge x,Edge y){
	return x.val>y.val;
}

int n,m,c,st,en,dis[N];
bool b[N];
vector<Edge> g[N];

void Dijkstra(){
	memset(dis,0x3f,sizeof(dis));
	priority_queue<Edge> q;
	dis[st]=0,q.push({st,0});
	while(q.size()){
		while(q.size() && b[q.top().to])
			q.pop();
		if(q.empty())
			break;
		int x=q.top().to;
		q.pop(),b[x]=1;
		for(Edge y:g[x])
			if(dis[y.to]>dis[x]+y.val){
				dis[y.to]=dis[x]+y.val;
				q.push({y.to,dis[y.to]});
			} 
	}
}

int main(){
	scanf("%d%d%d",&n,&m,&c);
	for(int i=1,u,v,w;i<=m;i++){
		scanf("%d%d%d",&u,&v,&w);
		g[u].push_back({v,w});
	}
	scanf("%d%d",&st,&en);
	for(int i=0;i<=n;i++)
		for(int j=0;(1<<j)<=n;j++)
			if((i^(1<<j))<=n) 
				g[i].push_back({(i^(1<<j)),(1<<j)*c});
	Dijkstra();
	printf("%d",dis[en]);
	return 0;
}
